from flask import Flask, request, jsonify
from flask_oauthlib.client import OAuth2Client

app = Flask(__name__)

# Initialize OAuth2Client with your client ID and secret
oauth_client = OAuth2Client(
    app,
    'your-client-id',
    'your-client-secret'
)

@app.route('/api/resource')
@oauth_client.require_oauth()
def resource():
    # Check if the access token is valid and exists in the database
    if not oauth_client.valid_token(request.headers['Authorization']):
        return jsonify({'error': 'Invalid or missing access token'}), 401

    # Return a response with the resource data
    return jsonify({'resource': 'This is a protected resource'})